import { notFound } from "next/navigation";

// 1. YOUR DATA AND TYPES
export type Major = { 
  slug: string; 
  name: string; 
  category: string; 
  demand: string; 
  description: string; 
  avgSalary: string; 
  jobOpenings: string; 
  duration: string; 
}; 

export const majors: Major[] = [ 
  { 
    slug: "computer-science", 
    name: "Computer Science", 
    category: "Engineering", 
    demand: "High Demand", 
    description: "Study algorithms, systems, and software design to build modern digital solutions.", 
    avgSalary: "$95,000", 
    jobOpenings: "1.2M+", 
    duration: "4 Years", 
  }, 
  { 
    slug: "business-administration", 
    name: "Business Administration", 
    category: "Business", 
    demand: "Medium Demand", 
    description: "Learn management, finance, and strategy for leading organizations effectively.", 
    avgSalary: "$70,000", 
    jobOpenings: "800K+", 
    duration: "3–4 Years", 
  }, 
];

// 2. THE PAGE COMPONENT (The Default Export)
export default async function MajorPage({ 
  params 
}: { 
  params: Promise<{ slug: string }> 
}) {
  const { slug } = await params;
  const major = majors.find((m) => m.slug === slug);

  // If major doesn't exist, show 404
  if (!major) return notFound();

  return (
    <div className="max-w-6xl mx-auto px-6 py-10 flex flex-col lg:flex-row gap-10">
      {/* HERO SECTION */}
      <div className="flex-1">
        <div className="flex gap-3 items-center mb-4">
          <span className="px-3 py-1 text-sm bg-gray-200 rounded-full font-medium text-gray-700">
            {major.category}
          </span>
          <span className="px-3 py-1 text-sm bg-green-100 text-green-700 rounded-full font-medium">
            {major.demand}
          </span>
        </div>
        <h1 className="text-4xl font-bold mb-4 text-gray-900">{major.name}</h1>
        <p className="text-gray-600 max-w-2xl leading-relaxed text-lg">
          {major.description}
        </p>
      </div>

      {/* STATS SIDEBAR */}
      <aside className="w-full lg:w-80 lg:sticky lg:top-20 h-fit border border-gray-200 rounded-xl p-6 shadow-sm bg-white">
        <h2 className="text-lg font-semibold mb-6 border-b pb-2">Key Stats</h2>
        <div className="space-y-5 text-sm">
          <div className="flex justify-between items-center">
            <span className="text-gray-500">Avg Salary</span>
            <span className="font-bold text-gray-900">{major.avgSalary}</span>
          </div>
          <div className="flex justify-between items-center">
            <span className="text-gray-500">Job Openings</span>
            <span className="font-bold text-gray-900">{major.jobOpenings}</span>
          </div>
          <div className="flex justify-between items-center">
            <span className="text-gray-500">Study Duration</span>
            <span className="font-bold text-gray-900">{major.duration}</span>
          </div>
        </div>
      </aside>
    </div>
  );
}

